                    Span {  } // should be <rgb(0, 0, 255)>
                }
                Span { } // should be <rgb(100, 100, 200)>
            }

            // Not a desc of "cls1"
            P { // should be <rgb(0, 0, 0)>
                Span {  } // should be <rgb(0, 0, 0)>
            }
        }

        root.children[1]!!.let { el ->
            val pEl = el.firstChild as HTMLParagraphElement
