            assertEquals(PluralCategory.OTHER, getCategory(-2))
            assertEquals(PluralCategory.ONE, getCategory(-1))
            assertEquals(PluralCategory.OTHER, getCategory(0))
            assertEquals(PluralCategory.ONE, getCategory(1))
            assertEquals(PluralCategory.OTHER, getCategory(2))
            assertEquals(PluralCategory.OTHER, getCategory(3))
        }

        pluralRuleListOf(
