fun Project.configureMavenPublication(
    groupId: String,
    artifactId: String,
    name: String
) {
    extensions.configure<PublishingExtension> {
        publications {
            all {
                this as MavenPublication

                this.groupId = groupId
                mppArtifactId = artifactId

                pom {
                    this.name.set(name)
